import{_ as o,o as i,c as d,ae as l}from"./chunks/framework.C7FLYIpo.js";const f=JSON.parse('{"title":"추론 수준","description":"/think, /fast, /verbose 및 추론 가시성을 위한 지시자 구문","frontmatter":{"title":"추론 수준","description":"/think, /fast, /verbose 및 추론 가시성을 위한 지시자 구문"},"headers":[],"relativePath":"tools/thinking.md","filePath":"tools/thinking.md","lastUpdated":null}'),c={name:"tools/thinking.md"};function t(a,e,n,r,s,h){return i(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="추론-수준-think-지시자" tabindex="-1">추론 수준 (/think 지시자) <a class="header-anchor" href="#추론-수준-think-지시자" aria-label="Permalink to &quot;추론 수준 (/think 지시자)&quot;">​</a></h1><h2 id="기능" tabindex="-1">기능 <a class="header-anchor" href="#기능" aria-label="Permalink to &quot;기능&quot;">​</a></h2><ul><li>모든 인바운드 본문의 인라인 지시자: <code>/t &lt;level&gt;</code>, <code>/think:&lt;level&gt;</code>, 또는 <code>/thinking &lt;level&gt;</code>.</li><li>수준 (별칭): <code>off | minimal | low | medium | high | xhigh | adaptive</code><ul><li>minimal → &quot;think&quot;</li><li>low → &quot;think hard&quot;</li><li>medium → &quot;think harder&quot;</li><li>high → &quot;ultrathink&quot; (최대 예산)</li><li>xhigh → &quot;ultrathink+&quot; (GPT-5.2 + Codex 모델 전용)</li><li>adaptive → 프로바이더 관리 적응형 추론 예산 (Anthropic Claude 4.6 모델 계열에서 지원됨)</li><li><code>x-high</code>, <code>x_high</code>, <code>extra-high</code>, <code>extra high</code>, <code>extra_high</code>는 <code>xhigh</code>에 매핑됩니다.</li><li><code>highest</code>, <code>max</code>는 <code>high</code>에 매핑됩니다.</li></ul></li><li>프로바이더 참고 사항: <ul><li>Anthropic Claude 4.6 모델은 명시적 추론 수준이 설정되지 않은 경우 기본적으로 <code>adaptive</code>를 사용합니다.</li><li>Anthropic 호환 스트리밍 경로의 MiniMax(<code>minimax/*</code>)는 모델 파라미터 또는 요청 파라미터에서 추론을 명시적으로 설정하지 않는 한 기본적으로 <code>thinking: { type: &quot;disabled&quot; }</code>로 설정됩니다. 이는 MiniMax의 비네이티브 Anthropic 스트림 형식에서 누출된 <code>reasoning_content</code> 델타를 방지합니다.</li><li>Z.AI(<code>zai/*</code>)는 이진 추론(<code>on</code>/<code>off</code>)만 지원합니다. <code>off</code>가 아닌 모든 수준은 <code>on</code>으로 처리됩니다(맵핑: <code>low</code>).</li><li>Moonshot(<code>moonshot/*</code>)은 <code>/think off</code>를 <code>thinking: { type: &quot;disabled&quot; }</code>로 매핑하고 <code>off</code>가 아닌 수준은 <code>thinking: { type: &quot;enabled&quot; }</code>로 매핑합니다. 추론이 활성화된 경우 Moonshot은 <code>tool_choice</code> <code>auto|none</code>만 허용합니다. OpenClaw는 호환되지 않는 값을 <code>auto</code>로 정규화합니다.</li></ul></li></ul><h2 id="결정-순서" tabindex="-1">결정 순서 <a class="header-anchor" href="#결정-순서" aria-label="Permalink to &quot;결정 순서&quot;">​</a></h2><ol><li>메시지의 인라인 지시자 (해당 메시지에만 적용).</li><li>세션 재정의 (지시자 전용 메시지를 전송하여 설정).</li><li>에이전트별 기본값 (설정의 <code>agents.list[].thinkingDefault</code>).</li><li>전역 기본값 (설정의 <code>agents.defaults.thinkingDefault</code>).</li><li>폴백: Anthropic Claude 4.6 모델은 <code>adaptive</code>, 기타 추론 가능 모델은 <code>low</code>, 그 외는 <code>off</code>.</li></ol><h2 id="세션-기본값-설정" tabindex="-1">세션 기본값 설정 <a class="header-anchor" href="#세션-기본값-설정" aria-label="Permalink to &quot;세션 기본값 설정&quot;">​</a></h2><ul><li><strong>오직</strong> 지시자만 포함된 메시지를 전송합니다 (공백 허용). 예: <code>/think:medium</code> 또는 <code>/t high</code>.</li><li>해당 설정은 현재 세션에 유지됩니다 (기본적으로 발신자별). <code>/think:off</code> 또는 세션 유휴 재설정으로 지워집니다.</li><li>확인 응답이 전송됩니다 (<code>Thinking level set to high.</code> / <code>Thinking disabled.</code>). 수준이 잘못된 경우 (예: <code>/thinking big</code>), 명령이 거부되고 힌트와 함께 세션 상태는 변경되지 않습니다.</li><li><code>/think</code> (또는 <code>/think:</code>)를 인수 없이 전송하면 현재 추론 수준을 확인할 수 있습니다.</li></ul><h2 id="에이전트별-적용" tabindex="-1">에이전트별 적용 <a class="header-anchor" href="#에이전트별-적용" aria-label="Permalink to &quot;에이전트별 적용&quot;">​</a></h2><ul><li><strong>임베디드 Pi</strong>: 결정된 수준이 인프로세스 Pi 에이전트 런타임에 전달됩니다.</li></ul><h2 id="빠른-모드-fast" tabindex="-1">빠른 모드 (/fast) <a class="header-anchor" href="#빠른-모드-fast" aria-label="Permalink to &quot;빠른 모드 (/fast)&quot;">​</a></h2><ul><li>수준: <code>on|off</code>.</li><li>지시자 전용 메시지는 세션 빠른 모드 재정의를 전환하고 <code>Fast mode enabled.</code> / <code>Fast mode disabled.</code>로 응답합니다.</li><li><code>/fast</code> (또는 <code>/fast status</code>)를 모드 없이 전송하면 현재 유효한 빠른 모드 상태를 확인할 수 있습니다.</li><li>OpenClaw는 다음 순서로 빠른 모드를 결정합니다: <ol><li>인라인/지시자 전용 <code>/fast on|off</code></li><li>세션 재정의</li><li>에이전트별 기본값 (<code>agents.list[].fastModeDefault</code>)</li><li>모델별 설정: <code>agents.defaults.models[&quot;&lt;provider&gt;/&lt;model&gt;&quot;].params.fastMode</code></li><li>폴백: <code>off</code></li></ol></li><li><code>openai/*</code>의 경우 빠른 모드는 지원되는 Responses 요청에서 <code>service_tier=priority</code>를 전송하여 OpenAI 우선 처리에 매핑됩니다.</li><li><code>openai-codex/*</code>의 경우 빠른 모드는 Codex Responses에 동일한 <code>service_tier=priority</code> 플래그를 전송합니다. OpenClaw는 두 인증 경로 모두에 걸쳐 하나의 공유 <code>/fast</code> 토글을 유지합니다.</li><li>OAuth 인증 트래픽을 포함하여 직접 공개 <code>anthropic/*</code> 요청의 경우 빠른 모드는 Anthropic 서비스 티어에 매핑됩니다. <code>/fast on</code>은 <code>service_tier=auto</code>, <code>/fast off</code>는 <code>service_tier=standard_only</code>로 설정합니다.</li><li>Anthropic 호환 경로의 <code>minimax/*</code>에서 <code>/fast on</code> (또는 <code>params.fastMode: true</code>)은 <code>MiniMax-M2.7</code>을 <code>MiniMax-M2.7-highspeed</code>로 재작성합니다.</li><li>명시적 Anthropic <code>serviceTier</code> / <code>service_tier</code> 모델 파라미터는 둘 다 설정된 경우 빠른 모드 기본값을 재정의합니다. OpenClaw는 비-Anthropic 프록시 베이스 URL에 대해 Anthropic 서비스 티어 주입을 건너뜁니다.</li></ul><h2 id="자세한-지시자-verbose-또는-v" tabindex="-1">자세한 지시자 (/verbose 또는 /v) <a class="header-anchor" href="#자세한-지시자-verbose-또는-v" aria-label="Permalink to &quot;자세한 지시자 (/verbose 또는 /v)&quot;">​</a></h2><ul><li>수준: <code>on</code> (최소) | <code>full</code> | <code>off</code> (기본값).</li><li>지시자 전용 메시지는 세션 자세한 출력을 전환하고 <code>Verbose logging enabled.</code> / <code>Verbose logging disabled.</code>로 응답합니다. 잘못된 수준은 상태를 변경하지 않고 힌트를 반환합니다.</li><li><code>/verbose off</code>는 명시적 세션 재정의를 저장합니다. 세션 UI에서 <code>inherit</code>를 선택하여 지울 수 있습니다.</li><li>인라인 지시자는 해당 메시지에만 영향을 미칩니다. 그 외에는 세션/전역 기본값이 적용됩니다.</li><li><code>/verbose</code> (또는 <code>/verbose:</code>)를 인수 없이 전송하면 현재 자세한 출력 수준을 확인할 수 있습니다.</li><li>자세한 출력이 켜져 있으면 구조화된 도구 결과를 내보내는 에이전트 (Pi, 기타 JSON 에이전트)는 각 도구 호출을 자체 메타데이터 전용 메시지로 전송합니다. 사용 가능한 경우 <code>&lt;emoji&gt; &lt;tool-name&gt;: &lt;arg&gt;</code> (경로/명령)로 접두사가 붙습니다. 이 도구 요약은 각 도구가 시작되는 즉시 전송됩니다 (별도 버블, 스트리밍 델타가 아님).</li><li>도구 실패 요약은 일반 모드에서도 표시되지만 자세한 출력이 <code>on</code> 또는 <code>full</code>이 아닌 경우 원시 오류 세부 정보 접미사는 숨겨집니다.</li><li>자세한 출력이 <code>full</code>인 경우 도구 출력도 완료 후 전달됩니다 (별도 버블, 안전한 길이로 잘림). 실행 중에 <code>/verbose on|full|off</code>를 전환하면 이후 도구 버블은 새 설정을 따릅니다.</li></ul><h2 id="추론-가시성-reasoning" tabindex="-1">추론 가시성 (/reasoning) <a class="header-anchor" href="#추론-가시성-reasoning" aria-label="Permalink to &quot;추론 가시성 (/reasoning)&quot;">​</a></h2><ul><li>수준: <code>on|off|stream</code>.</li><li>지시자 전용 메시지는 응답에 추론 블록이 표시되는지 여부를 전환합니다.</li><li>활성화된 경우 추론은 <code>Reasoning:</code>으로 접두사가 붙은 <strong>별도 메시지</strong>로 전송됩니다.</li><li><code>stream</code> (Telegram 전용): 응답이 생성되는 동안 Telegram 초안 버블에 추론을 스트리밍한 다음 추론 없이 최종 답변을 전송합니다.</li><li>별칭: <code>/reason</code>.</li><li><code>/reasoning</code> (또는 <code>/reasoning:</code>)을 인수 없이 전송하면 현재 추론 수준을 확인할 수 있습니다.</li><li>결정 순서: 인라인 지시자, 세션 재정의, 에이전트별 기본값 (<code>agents.list[].reasoningDefault</code>), 폴백 (<code>off</code>).</li></ul><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li>상승된 모드 문서는 <a href="/openclaw-docs-ko/tools/elevated">상승된 모드</a>에 있습니다.</li></ul><h2 id="하트비트" tabindex="-1">하트비트 <a class="header-anchor" href="#하트비트" aria-label="Permalink to &quot;하트비트&quot;">​</a></h2><ul><li>하트비트 프로브 본문은 구성된 하트비트 프롬프트입니다 (기본값: <code>Read HEARTBEAT.md if it exists (workspace context). Follow it strictly. Do not infer or repeat old tasks from prior chats. If nothing needs attention, reply HEARTBEAT_OK.</code>). 하트비트 메시지의 인라인 지시자는 일반적으로 적용됩니다 (단, 하트비트에서 세션 기본값 변경은 피하십시오).</li><li>하트비트 전달은 기본적으로 최종 페이로드만 전달합니다. 별도의 <code>Reasoning:</code> 메시지도 전송하려면 (사용 가능한 경우) <code>agents.defaults.heartbeat.includeReasoning: true</code> 또는 에이전트별 <code>agents.list[].heartbeat.includeReasoning: true</code>를 설정하십시오.</li></ul><h2 id="웹-채팅-ui" tabindex="-1">웹 채팅 UI <a class="header-anchor" href="#웹-채팅-ui" aria-label="Permalink to &quot;웹 채팅 UI&quot;">​</a></h2><ul><li>웹 채팅 추론 선택기는 페이지 로드 시 인바운드 세션 저장소/설정에서 저장된 세션의 수준을 미러링합니다.</li><li>다른 수준을 선택하면 다음 전송을 기다리지 않고 <code>sessions.patch</code>를 통해 세션 재정의가 즉시 작성됩니다. 이것은 일회성 <code>thinkingOnce</code> 재정의가 아닙니다.</li><li>첫 번째 옵션은 항상 <code>Default (&lt;resolved level&gt;)</code>이며, 여기서 결정된 기본값은 활성 세션 모델에서 가져옵니다. Anthropic/Bedrock의 Claude 4.6은 <code>adaptive</code>, 기타 추론 가능 모델은 <code>low</code>, 그 외는 <code>off</code>.</li><li>선택기는 프로바이더를 인식합니다: <ul><li>대부분의 프로바이더는 <code>off | minimal | low | medium | high | adaptive</code>를 표시합니다</li><li>Z.AI는 이진 <code>off | on</code>을 표시합니다</li></ul></li><li><code>/think:&lt;level&gt;</code>은 계속 작동하며 동일한 저장된 세션 수준을 업데이트하므로 채팅 지시자와 선택기는 동기화된 상태를 유지합니다.</li></ul>',21)])])}const g=o(c,[["render",t]]);export{f as __pageData,g as default};
